+  auto converted_ns = convert(approx_now);
+
+  constexpr libkineto::time_t kYear2020 = 1577836800LL * 1'000'000'000;
+  constexpr libkineto::time_t kYear2100 = 4102444800LL * 1'000'000'000;
+  EXPECT_GT(converted_ns, kYear2020);
